mapper.select:
select IFNULL(SUM(po.payable_total_amount),0)
from t_pay_order po


        and po.enterprise_id = #{queryForm.enterpriseId}


        and DATE_FORMAT(po.pay_time, '%Y-%m-%d') >= #{queryForm.verificationStartTime}


        and DATE_FORMAT(po.pay_time, '%Y-%m-%d') <= #{queryForm.verificationEndTime}


        and DATE_FORMAT(po.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(po.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and po.audit_status != #{queryForm.payOrderExcludeAuditStatus}
